#include <iostream>
#include <cstring>
using namespace std;

int main() {
    char str1[20] = "Hello";
    char str2[] = "World";
    char str3[10];

    // String length (excluding '\0')
    cout << "Length of str1: " << strlen(str1) << endl;

    // Copy
    strcpy(str3, str1);
    cout << "str3: " << str3 << endl;

    // Concatenate
    strcat(str1, " ");
    strcat(str1, str2);
    cout << "Concatenated: " << str1 << endl;

    // Compare
    if (strcmp(str1, "Hello World") == 0) {
        cout << "Equal" << endl;
    }

    // Danger: buffer overflow if not enough space
    char small[5];
    // strcpy(small, "Too long"); // BAD: buffer overflow
    strncpy(small, "Too long", 4);
    small[4] = '\0';
    cout << "Safe copy: " << small << endl;

    return 0;
}

