#include <iostream>
#include <string>
using namespace std;

int main() {
    string str = "Hello";

    // Access
    cout << "First char: " << str[0] << endl;
    cout << "Last char: " << str.back() << endl;
    cout << "Using at(): " << str.at(1) << endl;

    // Modify
    str[0] = 'h';
    str.back() = 'o';
    cout << str << endl;  // "hello"

    // Append
    str.append(" world");      // "hello world"
    str += "!";                // "hello world!"
    cout << str << endl;

    // Insert
    str.insert(5, " big");     // "hello big world!"
    cout << str << endl;

    // Replace
    str.replace(6, 3, "small"); // "hello small world!"
    cout << str << endl;

    // Erase
    str.erase(5, 6);           // remove " small"
    cout << str << endl;       // "hello world!"

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

int main() {
    string s = "Hello";
    cout << "Size: " << s.size() << endl;
    cout << "Length: " << s.length() << endl;  // same
    cout << "Capacity: " << s.capacity() << endl;

    s.resize(10, '!');
    cout << "After resize: " << s << endl;     // "Hello!!!!!"
    cout << "New size: " << s.size() << endl;

    s.reserve(100);  // preallocate capacity
    cout << "Capacity after reserve: " << s.capacity() << endl;

    s.shrink_to_fit();  // C++11, reduce capacity to fit size

    // Check empty
    string empty;
    if (empty.empty()) cout << "String is empty" << endl;

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

int main() {
    string str = "The quick brown fox jumps over the lazy dog";

    // Find first occurrence
    size_t pos = str.find("fox");
    if (pos != string::npos) {
        cout << "'fox' found at index " << pos << endl;
    }

    // Find from position
    pos = str.find("the", 10);  // find 'the' after index 10
    cout << "'the' found at " << pos << endl;

    // Find last occurrence
    pos = str.rfind("the");
    cout << "Last 'the' at " << pos << endl;

    // Find first of any characters
    pos = str.find_first_of("aeiou");
    cout << "First vowel at index " << pos << " -> " << str[pos] << endl;

    // Substring
    string sub = str.substr(10, 5);  // starting at 10, length 5
    cout << "Substring: " << sub << endl;  // "brown"

    // Substring to end
    string end = str.substr(40);
    cout << "From 40: " << end << endl;

    return 0;
}

