#include <iostream>
#include <string>
using namespace std;

int main() {
    string str = "Hello";

    // Index loop
    for (size_t i = 0; i < str.size(); i++) {
        cout << str[i] << " ";
    }
    cout << endl;

    // Range-based for (C++11)
    for (char c : str) {
        cout << c << " ";
    }
    cout << endl;

    // Iterator
    for (auto it = str.begin(); it != str.end(); ++it) {
        cout << *it << " ";
    }
    cout << endl;

    // Reverse iterator
    for (auto rit = str.rbegin(); rit != str.rend(); ++rit) {
        cout << *rit << " ";
    }
    cout << endl;

    // Modify in loop (reference)
    for (char& c : str) {
        c = toupper(c);
    }
    cout << str << endl;

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <sstream>
using namespace std;

int main() {
    // Reverse
    string s = "Hello World";
    reverse(s.begin(), s.end());
    cout << "Reversed: " << s << endl;

    // Palindrome check
    string word = "radar";
    string rev = word;
    reverse(rev.begin(), rev.end());
    if (word == rev) cout << word << " is palindrome" << endl;

    // Count characters
    string text = "hello hello";
    int count_l = count(text.begin(), text.end(), 'l');
    cout << "Number of 'l': " << count_l << endl;

    // Convert case
    string upper = text;
    transform(upper.begin(), upper.end(), upper.begin(), ::toupper);
    cout << "Uppercase: " << upper << endl;

    // Tokenization (split by space)
    string sentence = "C++ is fun";
    stringstream ss(sentence);
    string token;
    cout << "Tokens: ";
    while (ss >> token) {
        cout << token << " | ";
    }
    cout << endl;

    return 0;
}

#include <iostream>
#include <string>
#include <cstring>
using namespace std;

int main() {
    // std::string to C-string
    string cppStr = "Hello";
    const char* cstr = cppStr.c_str();   // pointer to internal null-terminated array
    cout << "C-string: " << cstr << endl;

    // Copy to mutable char array
    char buffer[20];
    strcpy(buffer, cppStr.c_str());
    buffer[0] = 'h';
    cout << "Buffer: " << buffer << endl;

    // C-string to std::string
    const char* old = "World";
    string newStr(old);   // or string newStr = old;
    cout << "std::string: " << newStr << endl;

    // Function that expects C-string
    void legacyFunc(const char* s) { cout << "Legacy: " << s << endl; }
    legacyFunc(cppStr.c_str());

    return 0;
}
